// イベント計画「ヒトマップ×山手線一周プロジェクト」に、既存の営業リード（client_leads）に
// 記録済みの5団体別ディープリサーチ（20260721追記）を統合したロードマップをmemoへ追記する。
// 各団体は接点の作り方（メール／電話／出展公募／会員制度）がバラバラなため、
// 同じ内容のメールを5件同時送信する現行の06_実行待機_Approval下書きの前提を見直す提案を含む。
// 使い方: node scripts/update-yamanote-roadmap-20260721.mjs
import { readFileSync } from 'node:fs';
import { createClient } from '@supabase/supabase-js';

function loadEnvLocal() {
  const text = readFileSync(new URL('../.env.local', import.meta.url), 'utf-8');
  for (const line of text.split('\n')) {
    const m = line.match(/^([A-Z_]+)=(.*)$/);
    if (m && !process.env[m[1]]) process.env[m[1]] = m[2].trim();
  }
}
loadEnvLocal();

const supabase = createClient(process.env.NEXT_PUBLIC_SUPABASE_URL, process.env.SUPABASE_SERVICE_ROLE_KEY, {
  auth: { autoRefreshToken: false, persistSession: false },
});

const TITLE = 'ヒトマップ×山手線一周プロジェクト（企画案 Ver.2）';

const ROADMAP_ADDENDUM = `

── ロードマップ（JR東日本本命営業に向けたプレイベント戦略・20260721）──

【全体方針】
本イベント（山手線1区間の探索イベント）は、単発の企画ではなく「JR東日本スタートアッププログラムへの本提案」に向けたプレイベント（実績づくり）と位置づける。まずこのイベントを実施し、その実施実績・参加者の声・写真を武器にJR東日本への提案を固め、採択後は沿線各所（恵比寿・渋谷・新宿）へと関係を広げていく順序で進める。JR以外の4団体（TCVB・サッポロ不動産開発・渋谷区観光協会・新宿観光振興協会）は、団体ごとに接点の作り方が異なる（client_leads memoのディープリサーチ参照）ため、プレイベント実施後にJR提案の進捗を見ながら個別に動く。

■フェーズ0（今週〜2週間）：プレイベントとしての第1回を実施
・山手線一周ではなく、まず1区間（恵比寿→渋谷、または新宿→渋谷）を「プレイベント」と明言して試験実施
・公共の場での実施のため団体の許可なく着手可能。既存ユーザー・協力者中心の少人数（5〜8名）で実施
・実施記録（写真・参加者の声・発見の連鎖という体験の質）をachievement-blogスキルで実績記事化し、「JR東日本スタートアッププログラムへ提案するための実証実績」として明確に作り込む

■フェーズ1（プレイベント直後〜1ヶ月）：JR東日本スタートアッププログラムへの本提案
・次回募集を「2026年春」としているが現在すでに7月のため、公式サイト（jrestartup.co.jp）で最新の募集要項・次回募集時期を再確認するのが最初の一手
・プレイベントの実績（体験記事・参加者の声）を携え、「駅・沿線を舞台にした体験実証」の型として提案書を作成（gov-proposal-customスキルの民間版として活用）
・営業推進部マネージャー・吉田知史氏など、プログラム説明を担当するキーパーソンへの接点を探る
・単独提案よりJR東日本の会員基盤（大人の休日倶楽部等）や沿線施設と絡めた座組みまで踏み込めると採択確度が上がる可能性がある点を提案に盛り込む

■フェーズ2（JR提案と並行、または採択後）：沿線各所との関係を広げる
・新宿観光振興協会：メールではなくまず電話ヒアリング（事務局 03-3344-3160）で接点を作る。プレイベントで新宿→渋谷ルートを実施済みなら、その実績をそのまま「区境を跨ぐ回遊企画」として提示できる
・サッポロ不動産開発（恵比寿ガーデンプレイス）：直接イベント提案はせず、まず恵比寿文化祭（例年10月）の出展公募（運営：mash-japan、Microsoft Forms、選考制）にプレイベントの実績を持って応募。採択後にサッポロ不動産開発本体へ単発共催を提案する二段階方式
・渋谷区観光協会：HACHI-8 PROJECT（8/7-9開催）は日程的に今年の本編参加は間に合わない可能性が高いため、今回は観察・ネットワーキングに絞る。観光フェロー制度または個人会員（年会費1万円）で接点を作り、事務局長・小池ひろよ氏への提案ルートを来年度に向けて準備する

■フェーズ3（JR採択後、または沿線協会との関係構築後）：TCVBは最後に、連合体制ができてから
・TCVBは個人事業単独では助成金に直接応募できず、地域資源発掘型プログラム事業は3団体以上の共同提案が必須（うち1団体は観光関連団体）
・渋谷区観光協会・新宿観光振興協会との関係が一定固まった段階で、両協会を巻き込んだ3団体以上の共同提案体制を組み、ヒトマップは企画・記録・コンテンツ制作の実行パートナーとして参画する

■フェーズ4（3ヶ月以降）：山手線一周の本編化・横展開
・JR東日本との関係構築、沿線各所との連携実績を積み上げた上で、正式な「山手線一周プロジェクト」の実施日を確定
・実施後はcase-study-pageスキルで事例記事化し、中央線・京浜東北線などJR他路線への横展開を検討（JR東日本との関係があれば横展開の提案もしやすくなる）

【KPI】
・プレイベント（1区間）実施1回、参加者5〜8名、実績記事1本
・JR東日本スタートアッププログラムへの提案書提出
・プレイベント後、4団体中2団体以上との実質的な接点確立

【リスクと対策】
・HACHI-8のタイミングを逃すと渋谷区観光協会との接点構築が来年度にずれ込む → 今回は無理に本編参加を狙わず観察・関係構築に絞ることでリスクを吸収
・JR提案の採択可否が見えるまで他4団体への本格営業を待つと機会損失になりうる → 新宿観光振興協会への電話ヒアリングなど低摩擦な接点作りはJR提案と並行して進めてよい
・06_実行待機_Approvalの5団体一斉送信メール下書きは、JR以外は「プレイベント実施後・団体別アプローチに作り直してから」に差し替えるのが望ましい`;

async function main() {
  const { data: current, error: fetchError } = await supabase
    .from('event_plans').select('id, memo').eq('title', TITLE).single();
  if (fetchError) { console.error(`✗ 取得失敗: ${fetchError.message}`); return; }

  const nextMemo = (current.memo ?? '') + ROADMAP_ADDENDUM;
  const { error } = await supabase
    .from('event_plans').update({ memo: nextMemo, status: 'planning' }).eq('id', current.id);
  if (error) console.error(`✗ 更新失敗: ${error.message}`);
  else console.log('✓ ロードマップを追記しました');
}

main();
